css:
.loader {color: var(--loader-color, #0f766e);
  --loader-secondary-color: #5eead4;
  --loader-bg: #ffffff;
  width: 64px;
  aspect-ratio: 1;
  display: grid;
}.loader:before {content: "";
  border: 8px solid var(--loader-color, #0f766e);
  border-radius: 50%;
  box-sizing: content-box;
  margin: auto;
  aspect-ratio: 1;
  animation: l2 infinite 1s steps(4,jump-none);
}@keyframes l2 {0% {width: 0% }to {width: 75%}}
